		"accepted_prompt_fingerprint": acceptedPromptFingerprint,
	}
	if actor := strings.TrimSpace(opts.Actor); actor != "" {
		body["actor"] = actor
	}
	if promptFingerprint := PromptFingerprint(*b); promptFingerprint != "" {
		body["prompt_fingerprint"] = promptFingerprint
	}
	payload, _ := json.Marshal(body)
	appendInlineEvent(b, BeadEvent{
		Kind:      "triaged",
		Summary:   "operator accepted proposed bead",
		Body:      string(payload),
		Actor:     strings.TrimSpace(opts.Actor),
		Source:    strings.TrimSpace(opts.Source),
		CreatedAt: time.Now().UTC(),
	})
}

func latestParkedIntakeFingerprint(b *Bead) (string, string) {
	if b == nil || b.Extra == nil {
		return "", ""
	}
	events := decodeBeadEvents(b.Extra["events"])
	for i := len(events) - 1; i >= 0; i-- {
		switch events[i].Kind {
		case "intake.blocked", "pre_claim_intake.blocked":
			fields := beadEventBodyFields(events[i].Body)
			fingerprint := strings.TrimSpace(fields["fingerprint"])
			if fingerprint == "" {
				continue
			}
			return fingerprint, strings.TrimSpace(fields["prompt_fingerprint"])
		}
	}
	return "", ""
}

func beadEventBodyFields(body string) map[string]string {
	fields := map[string]string{}
	if strings.TrimSpace(body) == "" {
		return fields
	}
	var raw map[string]any
	if err := json.Unmarshal([]byte(body), &raw); err != nil {
		return fields
	}
	for k, v := range raw {
		if s, ok := v.(string); ok {
			fields[k] = s
		}
	}
	return fields
}

// HeartbeatInterval is how often a claim owner should refresh the external
// claim liveness lease while running. Exposed as a variable so tests can
// override it.
var HeartbeatInterval = 30 * time.Second

// HeartbeatTTL is the maximum allowed age of the external claim liveness
// lease before another worker may reclaim the bead. Defaults to 3×
// HeartbeatInterval. Exposed as a variable so tests can override it.
var HeartbeatTTL = 90 * time.Second

// Claim sets a bead to in_progress with claim metadata.
// Fails if the bead is already claimed (status == in_progress) with a
// fresh claim lease. A bead whose external lease is older than HeartbeatTTL
// is considered stalled, except that a same-machine owner with a live PID is
// protected until the hard fallback ceiling expires.

package bead

import (
	"crypto/sha1"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const claimLivenessNamespace = "ddx-claim-heartbeats"

// claimLeaseSameMachineFallbackAge is the hard ceiling after which a same
// machine + live PID lease stops blocking takeover and we fall back to age.
// It stays comfortably above the lock-hold caps enforced elsewhere.
const claimLeaseSameMachineFallbackAge = 2 * time.Hour

type ClaimLeaseRecord struct {
	BeadID    string    `json:"bead_id"`
	Owner     string    `json:"owner,omitempty"`
	Session   string    `json:"session,omitempty"`
	Worktree  string    `json:"worktree,omitempty"`
	Machine   string    `json:"machine,omitempty"`
	StartedAt time.Time `json:"started_at,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`
	PID       int       `json:"pid,omitempty"`
}

func claimLivenessPath(ddxDir, id string) string {
	root := canonicalClaimRoot(ddxDir)
	sum := sha1.Sum([]byte(root))
	return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
}

func canonicalClaimRoot(ddxDir string) string {
	root := filepath.Clean(filepath.Dir(ddxDir))
	if abs, err := filepath.Abs(root); err == nil {
		root = abs
	}
	if real, err := filepath.EvalSymlinks(root); err == nil {
		root = real
	}
	return filepath.Clean(root)
}

func currentMachineID() string {
	machine, _ := os.Hostname()
	if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
		machine = envID
	}
	return machine
}

func writeAtomicClaimFile(path string, data []byte) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
	}
	tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
	if err != nil {
		return fmt.Errorf("bead: create claim liveness tmp: %w", err)
	}
	tmpName := tmp.Name()
	defer func() {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
	}()
	if _, err := tmp.Write(data); err != nil {
		return fmt.Errorf("bead: write claim liveness tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		return fmt.Errorf("bead: close claim liveness tmp: %w", err)
	}
	if err := os.Rename(tmpName, path); err != nil {
		return fmt.Errorf("bead: publish claim liveness: %w", err)
	}
	return nil
}

func (s *Store) writeClaimHeartbeat(rec ClaimLeaseRecord) error {
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, rec.BeadID), data)
}

func (s *Store) readClaimHeartbeat(id string) (ClaimLeaseRecord, bool, error) {
	data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
	if os.IsNotExist(err) {
		return ClaimLeaseRecord{}, false, nil
	}
	if err != nil {
		return ClaimLeaseRecord{}, false, fmt.Errorf("bead: read claim liveness: %w", err)
	}
	var rec ClaimLeaseRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return ClaimLeaseRecord{}, true, fmt.Errorf("bead: parse claim liveness: %w", err)
	}
	return rec, true, nil
}

func (s *Store) upsertClaimHeartbeat(id string, mutate func(*ClaimLeaseRecord)) error {
	rec, found, err := s.readClaimHeartbeat(id)
	if err != nil {
		return err
	}
	now := time.Now().UTC()
	if !found {
		rec = ClaimLeaseRecord{
			BeadID:    id,
			StartedAt: now,
		}
	}
	if rec.BeadID == "" {
		rec.BeadID = id
	}
	if rec.StartedAt.IsZero() {
		rec.StartedAt = now
	}
	rec.UpdatedAt = now
	if rec.PID == 0 {
		rec.PID = os.Getpid()
	}
	if mutate != nil {
		mutate(&rec)
	}
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, id), data)
}

func (s *Store) TouchClaimHeartbeat(id string) error {
	return s.upsertClaimHeartbeat(id, nil)
}

func (s *Store) RemoveClaimHeartbeat(id string) error {
	err := os.Remove(claimLivenessPath(s.Dir, id))
	if err == nil || os.IsNotExist(err) {
		return nil
	}
	return fmt.Errorf("bead: remove claim liveness: %w", err)
}

func (s *Store) ClaimHeartbeatFresh(id string) (bool, bool, error) {
	rec, found, err := s.readClaimHeartbeat(id)
	if err != nil {
		return false, false, err
	}
	if !found {
		return false, false, nil
	}
	if rec.UpdatedAt.IsZero() {
		return false, true, nil
	}
	return time.Since(rec.UpdatedAt) <= HeartbeatTTL, true, nil
}

// claimLeaseRecordIsStale reports whether the sidecar record can be taken
// over. Legacy rows without Machine/PID still fall back to age-only behavior.
func claimLeaseRecordIsStale(rec ClaimLeaseRecord) bool {
	if rec.UpdatedAt.IsZero() {
		return true
	}

	age := time.Since(rec.UpdatedAt)
	if age <= HeartbeatTTL {
		return false
	}

	if rec.Machine != "" && rec.Machine == currentMachineID() && rec.PID > 0 && processAlive(rec.PID) {
		return age > claimLeaseSameMachineFallbackAge
	}

	return true
}

// ClaimLease returns the external worker/manual claim sidecar for id when one
// exists. The record is the operator-facing live claim surface for workers; the
// tracker still carries any explicit manual lifecycle status change.
func (s *Store) ClaimLease(id string) (ClaimLeaseRecord, bool, error) {
	return s.readClaimHeartbeat(id)
}

