 62	// GetBeadSnapshots implements ddxgraphql.StateProvider.
 63	//
 64	// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
 65	// the resolver path opens exactly one project's store; a scoped query never
 66	// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
 67	// empty every registered project is scanned — that is still O(projects) by
 68	// necessity, but each project's bead.Store receives a pushed-down filter so
 69	// non-matching beads are never materialized as BeadSnapshot values.
 70	func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
 71		if projectID != "" {
 72			return s.GetBeadSnapshotsForProject(projectID, status, label, search)
 73		}
 74		projects := s.GetProjects()
 75		pred := beadFilterPredicate(status, label, search)
 76		var result []ddxgraphql.BeadSnapshot
 77		for _, proj := range projects {
 78			result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
 79		}
 80		return result
 81	}
