105	// beadSnapshotsForProjectEntry reads the single project's bead store, applies
106	// the (possibly nil) predicate at the store layer (filter pushdown), and
107	// returns GraphQL snapshots for the matching beads. Callers are responsible
108	// for deciding which projects to pass through — this helper never touches any
109	// other project's state.
110	func (s *ServerState) beadSnapshotsForProjectEntry(proj ProjectEntry, pred func(bead.Bead) bool) []ddxgraphql.BeadSnapshot {
111		if beadStoreOpenHook != nil {
112			beadStoreOpenHook(proj.Path)
113		}
114		store := bead.NewStore(ddxroot.JoinProject(proj.Path))
115		beads, err := store.ReadAllFiltered(context.Background(), pred)
116		if err != nil {
117			return nil
118		}
119		out := make([]ddxgraphql.BeadSnapshot, 0, len(beads))
120		for _, b := range beads {
121			snap := beadSnapshotFromStoreBead(proj.ID, b)
122			s.rememberBeadLocation(b.ID, proj, &snap)
123			out = append(out, snap)
124		}
125		return out
126	}
