128	// beadFilterPredicate returns a predicate suitable for bead.Store.ReadAllFiltered
129	// that applies status/label/search filters. A nil return means "match all".
130	func beadFilterPredicate(status, label, search string) func(bead.Bead) bool {
131		if status == "" && label == "" && search == "" {
132			return nil
133		}
134		q := strings.ToLower(search)
135		return func(b bead.Bead) bool {
136			if status != "" && b.Status != status {
137				return false
138			}
139			if label != "" && !containsString(b.Labels, label) {
140				return false
141			}
142			if q != "" {
143				if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
144					return false
145				}
146			}
147			return true
148		}
149	}
