    73	func NewStore(dir string, opts ...StoreOption) *Store {
    74		if dir == "" {
    75			dir = envOr("DDX_BEAD_DIR", ".ddx")
    76		}
    77		workingDir := dir
    78		if filepath.Base(dir) == ".ddx" {
    79			workingDir = filepath.Dir(dir)
    80		}
    81		prefix := envOr("DDX_BEAD_PREFIX", "")
    82		var configBackend string
