    84			if prefix == "" && cfg.Bead.IDPrefix != "" {
    85				prefix = cfg.Bead.IDPrefix
    86			}
    87			configBackend = cfg.Bead.Backend
    88		}
    89		if prefix == "" {
    90			prefix = detectPrefix(workingDir)
    91		}
    92		// Backend selection: env var wins, then config, then jsonl default.
    93		backendType := os.Getenv("DDX_BEAD_BACKEND")
    94		if backendType == "" {
    95			backendType = configBackend
    96		}
    97		if backendType == "" {
    98			backendType = BackendJSONL
    99		}
   100	
   101		s := &Store{
   102			Collection: DefaultCollection,
   103			Dir:        dir,
   104			Prefix:     prefix,
   105			LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
   106		}
   107		for _, opt := range opts {
   108			if opt != nil {
   109				opt(s)
   110			}
   111		}
   112		spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
   113		s.File, s.LockDir = spec.PathsUnder(dir)
   114	
   115		// Set up external backend if configured. bd/br lack per-collection
   116		// scoping in their CLI, so non-default collections (e.g. beads-archive)
   117		// route through a JSONL fallback the external backend transparently
   118		// delegates to. The default collection always goes straight to bd/br
   119		// to preserve the existing interchange contract (schema_compat_test.go,
   120		// import/export round-trip).
   121		switch backendType {
   122		case BackendBD, BackendBR:
   123			var fallback RawBackend
   124			if s.Collection != DefaultCollection {
   125				fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
   126			}
   127			if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
   128				s.backend = ext
   129			}
   130			// Fall through to JSONL if tool not available
   131		case BackendAxon:
   132			s.backend = NewAxonBackend(s.Dir, s.LockWait)
   133		}
