   312	func (s *Store) repairJSONL() (bool, error) {
   313		var repaired bool
   314		err := s.WithLock(func() error {
   315			beads, warnings, err := s.readAllRaw()
   316			if err != nil {
   317				return err
   318			}
   319			beads = foldLatestBeads(beads)
   320			if len(warnings) == 0 || len(beads) == 0 {
   321				return nil
   322			}
   323			backupPath := s.File + ".bak"
   324			backupData, err := os.ReadFile(s.File)
   325			if err != nil {
   326				return fmt.Errorf("read current file: %w", err)
   327			}
   328			if err := writeAtomicFile(backupPath, backupData); err != nil {
   329				return fmt.Errorf("write backup: %w", err)
   330			}
   331			if err := s.WriteAll(beads); err != nil {
   332				return fmt.Errorf("write repaired file: %w", err)
   333			}
   334			repaired = true
   335			return nil
   336		})
   337		return repaired, err
   338	}
