   340	func foldLatestBeads(beads []Bead) []Bead {
   341		if len(beads) == 0 {
   342			return nil
   343		}
   344	
   345		latest := make(map[string]Bead, len(beads))
   346		lastSeen := make(map[string]int, len(beads))
   347		for i, b := range beads {
   348			latest[b.ID] = b
   349			lastSeen[b.ID] = i
   350		}
   351	
   352		ids := make([]string, 0, len(latest))
   353		for id := range latest {
   354			ids = append(ids, id)
   355		}
   356		sort.Slice(ids, func(i, j int) bool {
   357			if lastSeen[ids[i]] != lastSeen[ids[j]] {
   358				return lastSeen[ids[i]] < lastSeen[ids[j]]
   359			}
   360			return ids[i] < ids[j]
   361		})
   362	
   363		out := make([]Bead, 0, len(ids))
   364		for _, id := range ids {
   365			out = append(out, latest[id])
   366		}
   367		return out
   368	}
