   455	func writeAtomicFile(path string, data []byte) error {
   456		tmp, err := tmpPath(path)
   457		if err != nil {
   458			return err
   459		}
   460		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
   461		if err != nil {
   462			return err
   463		}
   464		if _, err := f.Write(data); err != nil {
   465			f.Close()
   466			_ = os.Remove(tmp)
   467			return err
   468		}
   469		if err := f.Close(); err != nil {
   470			_ = os.Remove(tmp)
   471			return err
   472		}
   473		if err := os.Rename(tmp, path); err != nil {
   474			_ = os.Remove(tmp)
   475			return err
   476		}
   477		return nil
   478	}
